class McmcSampler(DoSampler):
    def build_bayesian_network(self, g, df):
        for node in nx.topological_sort(g):
            if g.nodes()[node]["parent_names"]:
                mu = g.nodes()[node]["parameters"][0]  # intercept
                mu += pm.math.dot(df[g.nodes()[node]["parent_names"]], g.nodes()[node]["parameters"][1:])
                if g.nodes()[node]["variable_type"] == "c":
                    sd = g.nodes()[node]["sd"]
                    g.nodes()[node]["variable"] = pm.Normal("{}".format(node), mu=mu, sd=sd, observed=df[node])
                elif g.nodes()[node]["variable_type"] == "b":
                    g.nodes()[node]["variable"] = pm.Bernoulli("{}".format(node), logit_p=mu, observed=df[node])
                else:
                    raise Exception("Unrecognized variable type: {}".format(g.nodes()[node]["variable_type"]))
        return g

    def fit_causal_model(self, g, df, data_types, initialization_trace=None):
        if nx.is_directed_acyclic_graph(g):
            with pm.Model() as model:
                g = self.apply_data_types(g, data_types)
                g = self.apply_parents(g)
                g = self.apply_parameters(g, df, initialization_trace=initialization_trace)
                g = self.build_bayesian_network(g, df)
                trace = pm.sample(1000, tune=1000)
        else:
            raise Exception("Graph is not a DAG!")
        return g, trace

    def do_x_surgery(self, g, x):
        for xi in x.keys():
            g.remove_edges_from([(parent, child) for (parent, child) in g.in_edges(xi)])
            g.nodes()[xi]["parent_names"] = []
        return g

    def do_sample(self, x):
        self.reset()
        g_for_surgery = nx.DiGraph(self.g)
        g_modified = self.do_x_surgery(g_for_surgery, x)
        self._df = self.make_intervention_effective(x)
        g_modified, trace = self.sample_prior_causal_model(
            g_modified, self._df, self._variable_types, initialization_trace=self.fit_trace
        )
        for col in self._df:
            if col in trace and col not in self._treatment_names:
                self._df[col] = trace[col]
        return self._df.copy()

def prefixset(nodes: set, ci_tester: CI_Tester, pset: set, verbose=False):
    """
    Outputting a larger prefix subset containting input prefix subset (pset)
    """

    d_set = set()
    for w in nodes - pset:
        w_in = 0
        for u in nodes:
            if w_in:
                break
            for v in nodes - pset - {w, u}:
                if ci_tester.is_ci(u, v, pset - {u}) and not ci_tester.is_ci(u, v, pset.union({w}) - {u}):
                    if verbose: print(f"Removing {w} from the prefix set")
                    d_set.add(w)
                    w_in = 1
                    break

    e_set = set()
    for w in nodes - pset - d_set:
        w_in = 0
        for u in pset - {w}:
            if w_in:
                break
            for v in nodes - pset - {w, u}:
                for v_p in nodes - pset - {w, u, v}:
                    if ci_tester.is_ci(u, v_p, pset.union({v}) - {u}) and not ci_tester.is_ci(u, v_p, pset.union({w, v}) - {u}):
                        if verbose: print(f"Removing {w} from the prefix set")
                        e_set.add(w)
                        w_in = 1
                        break

    f_set = set()
    for w in nodes - pset - d_set - e_set:
        w_in = 0
        for u in pset - {w}:
            if w_in:
                break
            for v in nodes - pset - {w, u}:
                if not ci_tester.is_ci(u, v, pset - {u}) and not ci_tester.is_ci(v, w, pset) and ci_tester.is_ci(u, w, pset.union({v})- {u}):
                    if verbose: print(f"Removing {w} from the prefix set")
                    f_set.add(w)
                    w_in = 1
                    break

    return nodes - d_set - e_set - f_set


def ccpg(nodes: set, ci_tester: CI_Tester, verbose=False):
    """
    CCPG algorithm
    """

    # Step 1: get lists of prefix subsets
    s = set()
    S = []
    while s != nodes:
        s = prefixset(nodes, ci_tester, s)
        # enforce termination when ci test are not perfect
        if len(S):
            if s == S[-1] and s != nodes:
                S.append(nodes)
                break
        if verbose: print(f"Prefix set: {s}")
        S.append(s)

    # Step 2: get components of ccpg
    components = []
    for i in range(len(S)):
        edges = set()
        cond_set = S[i-1] if i > 0 else set()
        for u, v in itertools.combinations(S[i]-cond_set, 2):
            if not ci_tester.is_ci(u, v, cond_set):
                edges.add(frozenset({u, v}))

        ug = nx.Graph()
        ug.add_nodes_from(S[i]-cond_set)
        ug.add_edges_from(edges)
        cc = connected_components(ug)
        if verbose: print(f"Connected components: {list(cc)}")
        components.extend([set(c) for c in connected_components(ug)])        

    # Step 3: get outer component edges
    edges = set()
    for i, j in itertools.combinations(range(len(components)), 2):
        cond_set = set().union(*components[:i-1]) if i > 0 else set()
        if not set_ci(ci_tester, components[i], components[j], cond_set):
            edges.add((i,j))

    return components, edges

